// Clean script for text-to-speech
const script = $input.first().json.script;

// Remove stage directions and markers
let cleanScript = script
  .replace(/\[PAUSE\]/g, '... ')
  .replace(/\[EMPHASIS\]/g, '')
  .replace(/\[VISUAL:.*?\]/g, '')
  .replace(/\[CTA:.*?\]/g, '')
  .replace(/\[.*?\]/g, '')
  .replace(/\s+/g, ' ')
  .trim();

// Extract visual cues for video generation
const visualCues = [];
const visualMatches = script.match(/\[VISUAL:(.*?)\]/g);
if (visualMatches) {
  visualMatches.forEach(match => {
    const cue = match.replace(/\[VISUAL:|\]/g, '').trim();
    visualCues.push(cue);
  });
}

// Extract CTAs
const ctas = [];
const ctaMatches = script.match(/\[CTA:(.*?)\]/g);
if (ctaMatches) {
  ctaMatches.forEach(match => {
    const cta = match.replace(/\[CTA:|\]/g, '').trim();
    ctas.push(cta);
  });
}

// Generate keywords for stock footage
const keywords = [
  'travel', 'adventure', 'destination', 'vacation',
  'backpacking', 'tourism', 'exploration', 'journey'
];

return {
  script_clean: cleanScript,
  script_original: script,
  visual_cues: visualCues,
  ctas: ctas,
  visual_keywords: keywords.join(' '),
  word_count: cleanScript.split(' ').length
};
